// 2022-01-18 - DFCT0010759 - "TaskerUtils" script include is generating errors 
// 2.7.3 | 2022-04-29 | raj | DFCT0010804 - "Organizational Unit Hierarchy Admin (OUHA)" is unable to "Deactivate OU" because they do NOT have permissions
// 2.8.4 | 2023-11-06 | raj | STRY0146507 - Certification Support- Placeholder - removed update call
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	var tcs = new TaskerCommonScriptingMethods();
	// DFCT0010759
	// var Utils = new taskerUtils();
	try {
		// setup fields needed by the rest of the script
		var answer = false;
		var activeTasksInfoMessage = "";
		var activeMembersInfoMessage = "";
		var activeChildrenInfoMessage = "";
		var ouHierarchyTableName = "x_153465_discovert_discover_office_hierarchy";
		var ouMembersTableName = "x_153465_discovert_discover_office_members";
		var taskTableName = "x_153465_discovert_route_task_instance";
		var user = gs.getUser();
		var globalOuRole = "x_153465_discovert.tasker_organizational_admin";
		var requiredRoles = [];
		var checkTemplateCreator = [];
		var processTemplateCreatorCheck = false;
		var ouId = current.sys_id;

		// check if children, members, tasks inactive
		var isOuDependentsActive = function() {
			var hasActive = false;
			var hasHierarchyChildren = false;
			var hasOuMembers = false;
			var hasTasks = false;

			var childrenQuery = [];
			childrenQuery.push({"parent":ouId});

			var ouMemberTableQuery = [];
			ouMemberTableQuery.push({"discover_office_hierarchy":ouId});

			var primaryAssigneeQuery = [];
			primaryAssigneeQuery.push({"primary_assignee":ouId});

			var primaryOfficeQuery = [];
			primaryOfficeQuery.push({"primary_office":ouId});

			var taskingAuthorityQuery = [];
			taskingAuthorityQuery.push({"organizational_unit":ouId});


			// check if any children active
			tcs.queryRelatedShort(ouHierarchyTableName, childrenQuery, function(record) {
				if(record.getValue("active") == true || record.getValue("u_active") == true) {
					hasActive = true;
					hasHierarchyChildren = true;
					return null;
				} else return false;
			}, true);

			// check if any members active
			tcs.queryRelatedShort(ouMembersTableName, ouMemberTableQuery, function(record) {
				hasOuMembers = true;
				hasActive = true;
				return null;
			}, true);

			// check if any tasks with ou in primary assignee active
			tcs.queryRelatedShort(taskTableName, primaryAssigneeQuery, function(record) {
				if(record.getValue("active") == true || record.getValue("u_active") == true) {
					hasActive = true;
					hasTasks = true;
					return null;
				} else return false;
			}, true);

			// check if any tasks with ou in primary office active
			tcs.queryRelatedShort(taskTableName, primaryOfficeQuery, function(record) {
				if(record.getValue("active") == true || record.getValue("u_active") == true) {
					hasActive = true;
					hasTasks = true;
					return null;
				} else return false;
			}, true);

			// if this ou is the tasking authority on any active tasks
			var taQuery = [{"tasking_authority": current.sys_id}, {"active": true}];
			// taSave is the sys_id of the TA that is referenced, so that we can point user to where it is enabled
			var taSave = "";
			tcs.queryRelatedShort(taskTableName, taQuery, function(record) {
					hasActive = true;
					hasTasks = true;
					taSave = current.sys_id;
					return null;
			}, true);
			return {
				"active":hasActive,
				"children":hasHierarchyChildren,
				"members":hasOuMembers,
				"tasks":hasTasks,
				"ta": taSave
			};
		};
		// this function constructs a link to the task where the TA is referenced, these tasks should first be disabled!
		var constructTaLink = function(ouSysId, taSysId) {
			return "../x_153465_discovert_route_task_instance_list.do?sysparm_query=primary_assignee%3D" + ouSysId + "%5ENQprimary_office%3D"
				+ ouSysId + "%5ENQtasking_authority%3D" + taSysId;
		};
		// this function sends a warning telling the user which items are still enabled.
		var notifyUserOfActive = function(activeSections) {
			var message = "";
			var membersLink = "<a href='../x_153465_discovert_discover_office_members_list.do?sysparm_query=discover_office_hierarchy%3D"+ouId+"'>link</a>";
			var ouLink = "<a href='../x_153465_discovert_discover_office_hierarchy_list.do?sysparm_query=parent%3D"+ouId+"%5Eactive%3Dtrue'>link</a>";
			var taskLink = "<a href='"+ constructTaLink(ouId, activeSections.ta) + "'>link</a>";
			if(activeSections.children) {
				message += "<br/> " + current.numberofchildous + " Sub OUs [" + ouLink + "]";
			} 
			if(activeSections.members) {
				message += "<br/> " +current.numberofmembersinou +" Members ["+ membersLink +"]";
			}
			//include a superficial +1 count if any tasks have a TA assigned, 
			// since we didnt include count of TA-only OU references as active tasks for this OU
			if(activeSections.tasks) {
				var taskFinalCount = current.numberofactivetasksinou;
				if(activeSections.ta && current.numberofactivetasksinou == 0) taskFinalCount += 1;
				message += "<br/> " + taskFinalCount +" or more Tasks where " + current.office_abbreviation + " is Primary Assignee, Primary Office and/or Tasking Authority ["+ taskLink +"]";
			}
			tcs.commonMessage("Organizational Hierarchy Active Dependencies", message + "<br/> Please remove dependendencies before deactivating this OU.", gs.addErrorMessage);
		};
		// check the roles to see if we can deactivate
		// DFCT0010804 - used previous b/c the check returns false if the OU is already inactive.  So, use previous in order to pass pass the active check
		var canDeactivateOU = new uiConditionCheck().canDeactivateOU(previous);
		if(canDeactivateOU) {
			var activeSections = isOuDependentsActive();
			if(!activeSections.active) {
				answer = true;
			} else {
				notifyUserOfActive(activeSections);
				answer = false;
			}
/* STRY0050440 - this role is not something that should be checked here.  This was not correct from the beginning.  And, the member check above would already cover looking up a specific permission on a member.  So, just dropping this completely.
		}
		  else if(tcs.checkUserForSingleRoleMatch(gs.getUser(), [singleOuRole])) {
			var activeSections2 = isOuDependentsActive();
			if(!activeSections2.active) {
				var userInfoScripts = new UserInfoScripts();
				var currentUserId = user.getID();
				if(ouId !== "" && userInfoScripts.IsUserInOU(ouId, currentUserId)) {
					answer = true;
				}
			} else {
				notifyUserOfActive(activeSections2);
				answer = false;
			}
*/			
		} else { // prevent user from deactivating without permissions
			answer = false;
			tcs.invalidPermissionsMessage("Organizational Hierarchy", "deactivation", gs.addInfoMessage);
			tcs.invalidPermissionsMessage("Organizational Hierarchy", "deactivation", gs.warn); //DEBUG
		}
		if(!answer) {
			// STRY0146507 - Certification Support- Placeholder - fixed removed update call
			current.active = previous.active;
		} else {
			// STRY0146507 - Certification Support- Placeholder - fixed removed update call
			current.active = false;
		}
	} catch(e) {

		// DFCT0010759 - eventually, this should change to a real utility called from everywhere for consitency.  
		//               For now, this util was only used 2 times so, backing it out.
		// var context = "OrgHierarchy - Mark as Inactive";
		// Utils.Catch(context, e);
		gs.error(gs.getMessage("Tasker | ") + gs.getMessage("OrgHierarchy - Mark as Inactive") + ": " + e.message + 
				gs.getMessage('LineNumber : ') + e.lineNumber + 
				gs.getMessage('SourceName : ') + e.sourceName +
				gs.getMessage('Name: ') + e.name + gs.getMessage('Message : ') + e.message);		
		// STRY0146507 - Certification Support- Placeholder - fixed removed update call
		current.active = previous.active;
	}
})(current, previous);
